UPDATE t_p28211681_photo_secure_web.legal_documents
SET content = REPLACE(
    content,
    '<p>11.3. Стороны освобождаются от ответственности при форс‑мажоре (ст.</p><p>401 ГК РФ).</p>',
    '<p>11.3. Стороны освобождаются от ответственности при наступлении обстоятельств Форс-мажора (п. 1.10 настоящей Оферты, ст. 401 ГК РФ). Исполнитель не несёт ответственности за неисполнение или ненадлежащее исполнение обязательств, если это вызвано Форс-мажором, в том числе:</p>'
    || '<ul>'
    || '<li>перебоями в работе сети Интернет, магистральных каналов связи, дата-центров или иных объектов инфраструктуры, не находящихся под управлением Исполнителя;</li>'
    || '<li>авариями, отключениями или ограничениями электроснабжения на объектах размещения оборудования;</li>'
    || '<li>действиями или бездействием операторов связи, хостинг-провайдеров, платёжных систем и иных третьих лиц, задействованных в предоставлении Сервиса;</li>'
    || '<li>DDoS-атаками, взломами, действиями вредоносного программного обеспечения и иными кибератаками на инфраструктуру Сервиса или его поставщиков;</li>'
    || '<li>блокировками, ограничениями или предписаниями со стороны государственных органов РФ или иных юрисдикций, в том числе Роскомнадзора, ФСТЭК, судебными решениями;</li>'
    || '<li>эпидемиями, пандемиями, введением режима повышенной готовности или чрезвычайного положения;</li>'
    || '<li>военными действиями, мобилизацией, введением санкций, эмбарго или иными ограничительными мерами, затрагивающими деятельность Исполнителя или его поставщиков;</li>'
    || '<li>стихийными бедствиями, пожарами, наводнениями, землетрясениями и иными природными катастрофами;</li>'
    || '<li>иными обстоятельствами, не зависящими от воли Исполнителя и находящимися вне его разумного контроля.</li>'
    || '</ul>'
    || '<p>11.4. При наступлении Форс-мажора Исполнитель по возможности уведомляет Заказчика через Сайт, e-mail или иными доступными способами в разумный срок. Срок исполнения обязательств продлевается на период действия обстоятельств Форс-мажора. Если такие обстоятельства продолжаются более 30 (тридцати) календарных дней, каждая из сторон вправе расторгнуть договор в порядке раздела 10; при этом Заказчику возвращается стоимость неиспользованного периода Подписки за вычетом фактически оказанных услуг.</p>'
)
WHERE slug = 'offer';